#include <stdio.h>
#define MOD 1000000007
long long p[12501];
int main() {
    int T, N, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        p[0] = 1;
        for (int i = 1; i <= M + N - 1; i++) {
            p[i] = 0;
            for (int j = 1; j <= i; j++) {
                if (i - j >= 0) p[i] = (p[i] + p[i - j]) % MOD;
            }
        }
        long long ans = 1;
        for (int i = M; i <= M + N - 1; i++) {
            ans = (ans * p[i]) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

